from gaze_tracking import GazeTracking
import cv2

gaze = GazeTracking()
webcam = cv2.VideoCapture(0)

while True:
    _, frame = webcam.read()
    gaze.refresh(frame)

    if gaze.is_blinking():
        print("Blinking")
    elif gaze.is_right():
        print("Looking right")
    elif gaze.is_left():
        print("Looking left")
